export default defineNuxtPlugin(() => {
  const localToken = localStorage.getItem("GithubTokenKey");
  if (localToken) {
    // 进入界面时，检查token
    checkIsAuthor(localToken)
      .then((res) => {
        if (res) {
            useGithubToken().value = localToken;
            notify({
                title: "Token验证成功!"
            });
        }
      });
  }
});
```
